#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

int last=1,tot=1,t,k;
long long f[N],g[N];
bool b[N];
char s[N];
vector<int> e[N];

struct Node{
    int son[26],len,fa;
}st[N];

void extend(int c){
    int p=last,np=last=++tot;
    st[np].len=st[p].len+1;
    f[tot]=1;
    for(;p && !st[p].son[c];p=st[p].fa) st[p].son[c]=np;
    if(!p){
        st[np].fa=1;
        return;
    }
    int q=st[p].son[c];
    if(st[q].len==st[p].len+1)
        st[np].fa=q;
    else{
        int nq=++tot;
        st[nq]=st[q],st[nq].len=st[p].len+1;
        st[q].fa=st[np].fa=nq;
        for(;p && st[p].son[c]==q;p=st[p].fa) st[p].son[c]=nq;
    }
}

void dfs(int x){
    for(int y:e[x]){
        dfs(y);
        f[x]+=f[y];
    }
}

void dfs2(int x){
    if(b[x]) return;
    b[x]=1;
    if(t) g[x]=f[x];
    else g[x]=(x>1);
    for(int i=0;i<26;i++){
        if(!st[x].son[i]) continue;
        dfs2(st[x].son[i]);
        g[x]+=g[st[x].son[i]];
    }
}

int main(){
    scanf("%s",s);
    scanf("%d%d",&t,&k);
    for(int i=0;s[i];i++) extend(s[i]-'a');
    for(int i=2;i<=tot;i++)
        e[st[i].fa].push_back(i);
    dfs(1);
    f[1]=0;
    dfs2(1);
    if(g[1]<k){
        puts("-1");
        return 0;
    }
    for(int p=1;k>0;){
        for(int i=0;i<26;i++)
            if(st[p].son[i]){
                if(g[st[p].son[i]]>=k){
                    printf("%c",i+'a');
                    p=st[p].son[i];
                    if(t) k-=f[p];
                    else k--;
                    break;
                }else
                    k-=g[st[p].son[i]];
            }
    }
    return 0;
}
